const topic = (msg.topic ?? '').toString();
const payload = msg.payload;

// topic 예:
// - cronusfarm/sensor/temp
// - cronusfarm/actuator/led_a1
// - cronusfarm/sensor/3178/ph

const parts = topic.split('/').filter(Boolean);
if (parts.length < 3) return null;

const domain = parts[1];   // sensor|actuator
const rest = parts.slice(2);
const key = rest.join('/');

// 값 숫자화(실패 시 문자열로 저장)
let num = Number(payload);
const isNum = Number.isFinite(num);

msg.payload = [{
  measurement: domain,
  tags: {
    key,
  },
  fields: isNum ? { value: num } : { value_str: (payload ?? '').toString() },
  timestamp: new Date()
}];
return msg;
